import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { TranslateService } from "@ngx-translate/core";
import { EnvService } from "src/app/core/services/env.service";
import { Permission } from "src/app/views/Models/Permissions/Permission";
import {
  BranchReference,
  UserBranch,
} from "src/app/views/Models/Settings/BranchReference";
import { User } from "src/app/views/Models/Permissions/User";
import { BankForUser } from "src/app/views/Models/Banks/BankForUser";
import { pagingService } from "src/app/core/services/paging.service";
import { UserService } from "src/app/core/services/user.service";
import { FormBuilder, FormGroup } from "@angular/forms";

@Component({
  selector: "app-add-banks-for-user",
  templateUrl: "./add-banks-for-user.page.html",
  styleUrls: ["./add-banks-for-user.page.scss"],
})
export class AddBanksForUserPage implements OnInit {
  showLoader: boolean = false;
  initialLoad: boolean = true;

  page = 1;

  days: string[][];
  permissions: Permission[] = [];
  BranchReferences: BranchReference[] = [];
  selectedUser: User;
  BanksForUser: BankForUser[] = [];
  filteredBanks: BankForUser[] = [];

  selectedPermission: BranchReference[];
  selectedAllPermissions: boolean;

  constructor(
    private env: EnvService,
    private http: HttpClient,
    public translate: TranslateService,
    public pagingService: pagingService,
    public userService: UserService,
    private formBuilder: FormBuilder
  ) {}

  SearchForm: FormGroup = this.formBuilder.group({
    search_input: [""],
  });

  async ngOnInit() {
    this.GetBranches();
  }

  ngOnDestroy(): void {}

  GetBranches() {
    this.showLoader = true;
    this.http
      .get<BranchReference[]>(this.env.API_URL + `api/Branch/GetAllBranches`)
      .subscribe({
        next: (data) => {
          this.BranchReferences = data["BranchReferences"];
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  userSelected(user: User): void {
    this.selectedUser = user;
    this.showLoader = true;
    this.http
      .get<BankForUser[]>(
        this.env.API_URL + `api/Bank/GetUserBanks?username=${user.user_name}`
      )
      .subscribe({
        next: (data) => {
          this.BanksForUser = data;
          this.filteredBanks = this.BanksForUser;
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }
  DeselectUser() {
    this.selectedUser = null;
    this.page = 1;
    this.SearchForm.controls.search_input.reset();
  }
  ChangePermissions(BankForUser: BankForUser[], value: number): void {
    this.showLoader = true;
    if (value === 1) {
      this.http
        .post(
          this.env.API_URL +
            `api/Bank/AddUserAllBanks?user_name=${this.selectedUser.user_name}`,
          {}
        )
        .subscribe({
          next: () => {
            BankForUser.forEach((x) => {
              x.have_rights = 1;
            });
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    } else {
      this.http
        .post(
          this.env.API_URL +
            `api/Bank/RemoveUserAllBanks?user_name=${this.selectedUser.user_name}`,
          {}
        )
        .subscribe({
          next: () => {
            BankForUser.forEach((x) => {
              x.have_rights = 0;
            });
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    }
  }
  ChangePermission(BankForUser: BankForUser, value: number): void {
    this.showLoader = true;

    if (value === 1) {
      this.http
        .post(
          this.env.API_URL +
            `api/Bank/AddUserBank?user_name=${this.selectedUser.user_name}&bank_key=${BankForUser.bank_key}`,
          {}
        )
        .subscribe({
          next: () => {
            BankForUser.have_rights = 1;
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    } else {
      this.http
        .post(
          this.env.API_URL +
            `api/Bank/RemoveUserBank?user_name=${this.selectedUser.user_name}&bank_key=${BankForUser.bank_key}`,
          {}
        )
        .subscribe({
          next: () => {
            BankForUser.have_rights = 0;
            this.showLoader = false;
          },
          error: (err) => {
            console.log(err.message);
            this.showLoader = false;
          },
        });
    }
  }
  checkAllBanksForUserEnable(BanksForUser: BankForUser[]): boolean {
    return BanksForUser.every((item) => item.have_rights == 1);
  }
  checkAllBanksForUserDisable(BanksForUser: BankForUser[]): boolean {
    return BanksForUser.every((item) => item.have_rights == 0);
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  searchForUsers() {
    this.page = 1;
    let bank_name = this.SearchForm.value.search_input;

    this.filteredBanks = this.BanksForUser.filter(
      (v) =>
        bank_name == "" ||
        v.bank_name.toLowerCase().match(bank_name.toLowerCase())
    );
  }
}
